import { NavBar } from "./NavBar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";
export function Login(){

    const[email,setEmail]=useState("");
    const[lozinkaHash,setLozinka]=useState("");
      const imeRef = useRef(null);

      const navigate=useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

const handleSubmit = async (e) => {
  e.preventDefault();

  try {
    const response = await fetch(`http://localhost:8080/guests/login/${email}/${lozinkaHash}`, {
      method: "GET"
    });

    if (response.ok) {
      const data = await response.json();

      // Pretpostavimo da backend vraća ID gosta
      const userId = data.idGost;  

      // Postavljanje cookie-a na 1 dan
      const expiration = new Date();
      expiration.setDate(expiration.getDate() + 1);
      document.cookie = `userId=${userId}; expires=${expiration.toUTCString()}; path=/`;

      console.log("Uspesan login, cookie postavljen:", document.cookie);

      navigate("/");
    } else {
      const data = await response.json();
      alert(`Neuspesan login! ${data.message || ""}`);
    }
  } catch (error) {
    console.error("Greska prilikom login-a:", error);
    alert("Server nije dostupan.");
  }
};

return(
    <>
    <NavBar />
    <div style={{ backgroundImage: `url(${pattern})`,
    backgroundSize: "cover",   
    backgroundPosition: "center",
    minHeight: "100vh",         
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column"}}>
    <div className="forma" style={{with:"300px",height:"300px"}}>
        <form onSubmit={handleSubmit}>

        <span className="formaSpan">
            Unesite email
            <input type="email" onChange={(e)=>setEmail(e.target.value)} ref={imeRef} required />

        </span>
       <span className="formaSpan">
            Unesite lozinku
            <input type="password" onChange={(e)=>setLozinka(e.target.value)} required/>
        </span>

       <button type="submit" className="btnNav" style={{marginTop:"20px",border: "none",fontSize:"18px",width:"160px",height:"50px"}}>Napravi nalog</button>


</form>

    </div>
    </div>
    <Footer />
    </>
)


}
